{
  "schema_name": "eywa_node_response",
  "schema_version": "v1",
  "orchestration_decision": "delegate",
  "decision_notes": "The problem requires calculating the Rydberg energy for a specific exciton state using the relationship between the band gap and the exciton binding energy. The sign convention is critical as exciton energy levels are typically expressed as negative relative to the conduction band edge.",
  "helpers": [
    {
      "label": "extract_parameters",
      "instructions": "Identify and list the numerical values for the band gap (Eg) and the energy of the 1s exciton peak (E_1s) from the problem statement. Ensure units are consistent in electron volts (eV)."
    },
    {
      "label": "calculate_rydberg_constant",
      "instructions": "Calculate the exciton Rydberg energy (Ry*) using the relationship between the band gap and the 1s exciton energy. The formula is Ry* = (Eg - E_1s) / 2. Note that for a hydrogenic model, the 1s binding energy is equal to Ry*. Provide the result in eV."
    },
    {
      "label": "calculate_n3_energy_level",
      "instructions": "Using the Rydberg energy (Ry*) calculated in the previous step, calculate the energy level for the n = 3 state. The formula for the energy of the nth state relative to the band gap is E_n = Eg - (Ry* / n^2). Alternatively, if the question asks for the binding energy level relative to the conduction band edge, use E_n_binding = - (Ry* / n^2). Given the instruction that sign matters, calculate the energy level relative to the conduction band edge (the vacuum level/band edge reference) which is - (Ry* / n^2). Provide the final value in eV."
    }
  ],
  "synthesis_brief": "Combine the extracted parameters and the calculated Rydberg constant to find the specific energy level for n=3. Ensure the final answer reflects the correct sign convention for an exciton state relative to the conduction band edge (typically a negative value)."
}

